   * another representation can preserve the origin tag without a
   * post-call spread.
   */
  fromOklch(
    l: number,
    c: number,
    h: number,
    opts?: { 'alpha'?: number; 'hints'?: ColorHintsInterfaceType | undefined; 'sourceFormat'?: SourceFormatType; }
  ): ColorRecordInterfaceType {
    const { alpha = 1, hints, sourceFormat = 'oklch' } = opts ?? {};
    const mapped = gamutMapSrgb.apply(l, c, h);
    const rgb    = oklchToRgbRaw.apply(mapped.l, mapped.c, mapped.h);

    let displayP3: { 'b': number; 'g': number; 'r': number; } | undefined;
    if (!mapped.inGamut) {
      const p3 = oklchToDisplayP3.apply(l, c, h);
      displayP3 = {
        'b': clamp01.apply(p3.b),
        'g': clamp01.apply(p3.g),
        'r': clamp01.apply(p3.r)
      };
    } else {
      displayP3 = undefined;
    }

    return {
      'alpha':        clamp01.apply(alpha),
      'displayP3':    displayP3,
      'hex':          rgbToHex.apply(rgb.r, rgb.g, rgb.b),
      'hints':        hints,
      'oklch':        { 'c': clamp.apply(0, 0.5, c), 'h': ((h % 360) + 360) % 360, 'l': clamp01.apply(l) },
      'rgb':          rgb,
      'sourceFormat': sourceFormat
    };
  }

  /**
   * Builds a record from gamma-encoded sRGB components in 0..1. Inputs
   * outside the unit range are clamped, not scaled; pass `r/255` if
   * starting from byte values. The OKLCH coordinates are derived via
   * Björn Ottosson's OKLab transform.
   *
   * `sourceFormat` defaults to `'rgb'` but accepts any
   * {@link SourceFormatType} so intake handlers that compute through
   * RGB (lab, hsl, imagePixel, ...) can tag the record with the format
   * they actually consumed.
   */
  fromRgb(
    r: number,
    g: number,
    b: number,
    opts?: { 'alpha'?: number; 'hints'?: ColorHintsInterfaceType | undefined; 'sourceFormat'?: SourceFormatType; }
  ): ColorRecordInterfaceType {
    const { alpha = 1, hints, sourceFormat = 'rgb' } = opts ?? {};
    const oklch = rgbToOklchRaw(r, g, b);
    return {
      'alpha':        clamp01.apply(alpha),
      'displayP3':    undefined,
      'hex':          rgbToHex.apply(r, g, b),
      'hints':        hints,
      'oklch':        oklch,
      'rgb':          { 'b': clamp01.apply(b), 'g': clamp01.apply(g), 'r': clamp01.apply(r) },
      'sourceFormat': sourceFormat
    };
  }

  /**
   * Parses `#rrggbb` or `#rrggbbaa` (case-insensitive, leading `#`
   * optional). Throws on any other length or non-hex characters. The
   * returned record's `hex` field is always the canonical 6-digit form;
   * any 8-digit alpha is split off into the `alpha` field so downstream
   * code never has to deal with two encodings.
   *
   * The optional `alphaOverride` argument lets callers (notably
   * `IntakeHex`) supply an alpha derived elsewhere, useful when the
   * hex string is the 6-digit canonical form but the original input
   * carried a separate alpha. When `undefined`, the alpha embedded in
   * the hex string (or `1` for 6-digit input) is used.
   */
  fromHex(
    hex: string,
    opts?: { 'alphaOverride'?: number; 'hints'?: ColorHintsInterfaceType | undefined; 'sourceFormat'?: SourceFormatType; }
  ): ColorRecordInterfaceType {
    const { alphaOverride, hints, sourceFormat = 'hex' } = opts ?? {};
    const cleaned = hex.replace(/^#/, '');
    if (!/^[0-9a-fA-F]{6}(?:[0-9a-fA-F]{2})?$/.test(cleaned)) {
      throw ValidationError.create({
        'message': 'ColorRecordFactory.fromHex: invalid hex string',
        'path':    'hex',
        'violations': [{
          'details': { 'expectedFormat': '6 or 8 hex digits, with or without leading #', 'received': hex },
          'message': 'value is not a valid hex color string',
          'path':    'hex'
        }]
      });
    }
    const r = parseInt(cleaned.slice(0, 2), 16) / 255;
    const g = parseInt(cleaned.slice(2, 4), 16) / 255;
    const b = parseInt(cleaned.slice(4, 6), 16) / 255;
    const parsedAlpha = cleaned.length === 8
      ? parseInt(cleaned.slice(6, 8), 16) / 255
      : 1;
    const alpha = alphaOverride ?? parsedAlpha;
    const oklch = rgbToOklchRaw(r, g, b);
    return {
      'alpha':        clamp01.apply(alpha),
      'displayP3':    undefined,
      'hex':          `#${cleaned.slice(0, 6).toLowerCase()}`,
      'hints':        hints,
      'oklch':        oklch,
      'rgb':          { 'b': b, 'g': g, 'r': r },
      'sourceFormat': sourceFormat
    };
  }

  /**
   * Builds a record from HSL coordinates. `h` is degrees (wrapped into
   * [0, 360)); `s` and `l` are 0..1. The HSL → RGB conversion uses the
   * standard piecewise formula, then derives OKLCH and hex from the
   * RGB triple. `sourceFormat` defaults to `'hsl'`.
   */
  fromHsl(
    h: number,
    s: number,
    l: number,
    opts?: { 'alpha'?: number; 'hints'?: ColorHintsInterfaceType | undefined; 'sourceFormat'?: SourceFormatType; }
  ): ColorRecordInterfaceType {
    const { alpha = 1, hints, sourceFormat = 'hsl' } = opts ?? {};
    const rgb = hslToRgbRaw(h, s, l);
    return this.fromRgb(rgb.r, rgb.g, rgb.b, { 'alpha': alpha, 'hints': hints, 'sourceFormat': sourceFormat });
  }
}

/**
 * Process-wide singleton instance. Stateless; safe to share across
 * engines and modules. The registry assumes this exact reference.
 */
export const colorRecordFactory = new ColorRecordFactory();
// Delta E 2000 computed via OKLCH-derived Lab (D65). OKLCH is a direct reparametrisation
// of OKLab, so (L, a*, b*) = (oklch.l, c*cos(h), c*sin(h)) in the OKLab encoding.
// The CIE ΔE 2000 formula is applied to these Lab values per Sharma et al. 2005.
import type { ColorRecordInterfaceType } from '../types/index.ts';

function oklchToOklab(l: number, c: number, h: number): [number, number, number] {
  const hRad = (h * Math.PI) / 180;
  return [l, c * Math.cos(hRad), c * Math.sin(hRad)];
}

function deg(rad: number): number {
  return (rad * 180) / Math.PI;
}

function rad(d: number): number {
  return (d * Math.PI) / 180;
}

class DeltaE2000 {
  readonly 'name' = 'deltaE2000';

  apply(a: ColorRecordInterfaceType, b: ColorRecordInterfaceType): number {
    const [L1, a1, b1] = oklchToOklab(a.oklch.l, a.oklch.c, a.oklch.h);
    const [L2, a2, b2] = oklchToOklab(b.oklch.l, b.oklch.c, b.oklch.h);

    // OKLab L is 0..1; CIE Lab L is 0..100. Scale so the formula's hard-coded
    // constants (Sharma et al. 2005) operate on the magnitudes they expect.
    const scale = 100;
    const sa1 = a1 * scale; const sb1 = b1 * scale; const sL1 = L1 * scale;
    const sa2 = a2 * scale; const sb2 = b2 * scale; const sL2 = L2 * scale;

    const C1 = Math.sqrt(sa1 * sa1 + sb1 * sb1);
    const C2 = Math.sqrt(sa2 * sa2 + sb2 * sb2);
    const Cavg = (C1 + C2) / 2;
    const C7 = Math.pow(Cavg, 7);
    const factor25_7 = Math.pow(25, 7);
    const G = 0.5 * (1 - Math.sqrt(C7 / (C7 + factor25_7)));

    const a1p = sa1 * (1 + G);
    const a2p = sa2 * (1 + G);
    const C1p = Math.sqrt(a1p * a1p + sb1 * sb1);
    const C2p = Math.sqrt(a2p * a2p + sb2 * sb2);

    let h1p = deg(Math.atan2(sb1, a1p));
    if (h1p < 0) {h1p += 360;}
    let h2p = deg(Math.atan2(sb2, a2p));
    if (h2p < 0) {h2p += 360;}

    const dLp = sL2 - sL1;
    const dCp = C2p - C1p;

    let dhp = 0;
    if (C1p * C2p === 0) {
      dhp = 0;
    } else if (Math.abs(h2p - h1p) <= 180) {
      dhp = h2p - h1p;
    } else if (h2p - h1p > 180) {
      dhp = h2p - h1p - 360;
    } else {
      dhp = h2p - h1p + 360;
    }

    const dHp = 2 * Math.sqrt(C1p * C2p) * Math.sin(rad(dhp / 2));

    const Lp = (sL1 + sL2) / 2;
    const Cp = (C1p + C2p) / 2;

    let Hp = 0;
    if (C1p * C2p === 0) {
      Hp = h1p + h2p;
    } else if (Math.abs(h1p - h2p) <= 180) {
      Hp = (h1p + h2p) / 2;
    } else if (h1p + h2p < 360) {
      Hp = (h1p + h2p + 360) / 2;
    } else {
      Hp = (h1p + h2p - 360) / 2;
    }

    const T = 1
      - 0.17 * Math.cos(rad(Hp - 30))
      + 0.24 * Math.cos(rad(2 * Hp))
      + 0.32 * Math.cos(rad(3 * Hp + 6))
      - 0.20 * Math.cos(rad(4 * Hp - 63));

    const SL = 1 + 0.015 * Math.pow(Lp - 50, 2) / Math.sqrt(20 + Math.pow(Lp - 50, 2));
    const SC = 1 + 0.045 * Cp;
    const SH = 1 + 0.015 * Cp * T;

    const Cp7 = Math.pow(Cp, 7);
    const RC = 2 * Math.sqrt(Cp7 / (Cp7 + factor25_7));
    const dTheta = 30 * Math.exp(-Math.pow((Hp - 275) / 25, 2));
    const RT = -Math.sin(rad(2 * dTheta)) * RC;

    const kC = 1; const kH = 1; const kL = 1;
    return Math.sqrt(
      Math.pow(dLp  / (kL * SL), 2) +
      Math.pow(dCp  / (kC * SC), 2) +
      Math.pow(dHp  / (kH * SH), 2) +
      RT * (dCp / (kC * SC)) * (dHp / (kH * SH))
    );
  }
}

/** Singleton instance registered as the `deltaE2000` math primitive. */
export const deltaE2000 = new DeltaE2000();
import { ValidationError } from '@studnicky/errors';

import type { ColorRecordInterfaceType } from '../types/index.ts';

import { colorRecordFactory } from './ColorRecordFactory.ts';
import { deltaE2000 } from './DeltaE2000.ts';

type ClusterInterface = {
  'centroid':  ColorRecordInterfaceType;
  'weight':    number;
};

function recordWeight(record: ColorRecordInterfaceType): number {
  const w = record.hints?.weight;
  return typeof w === 'number' && w > 0 ? w : 1;
}

/**
 * Builds a centroid record from two clusters by weighted-averaging in
 * OKLab space (a*, b* are the rectangular Cartesian projection of
 * chroma+hue) so hue wrap-around is handled by the projection rather
 * than by a circular-mean correction.
 */
class Centroids {
  static merge(a: ClusterInterface, b: ClusterInterface): ClusterInterface {
    // Treat zero-weight inputs as weight=1 so the weighted average stays
    // defined. A zero-weight cluster is degenerate (the upstream task
    // should not produce one), but guarding here keeps a single bad input
    // from NaN-poisoning every subsequent merge.
    const wa = a.weight > 0 ? a.weight : 1;
    const wb = b.weight > 0 ? b.weight : 1;
    const tot = wa + wb;
    const aRad = (a.centroid.oklch.h * Math.PI) / 180;
    const bRad = (b.centroid.oklch.h * Math.PI) / 180;
    const aA = a.centroid.oklch.c * Math.cos(aRad);
    const aB = a.centroid.oklch.c * Math.sin(aRad);
    const bA = b.centroid.oklch.c * Math.cos(bRad);
    const bB = b.centroid.oklch.c * Math.sin(bRad);
    const L = (a.centroid.oklch.l * wa + b.centroid.oklch.l * wb) / tot;
    const aMean = (aA * wa + bA * wb) / tot;
    const bMean = (aB * wa + bB * wb) / tot;
    const C = Math.sqrt(aMean * aMean + bMean * bMean);
    let H = (Math.atan2(bMean, aMean) * 180) / Math.PI;
    if (H < 0) {H += 360;}
    const alpha = (a.centroid.alpha * wa + b.centroid.alpha * wb) / tot;
    return {
      'centroid': colorRecordFactory.fromOklch(L, C, H, { 'alpha': alpha, 'hints': { 'weight': tot }, 'sourceFormat': 'oklch' }),
      'weight':   tot
    };
  }
}

/**
 * Agglomerative deltaE2000 clustering. Each input record starts as its
 * own cluster; the algorithm repeatedly merges the closest pair (in
 * deltaE2000) until exactly K clusters remain. Distances are recomputed
 * for the new centroid after every merge.
 *
 * Output records carry `hints.weight` set to the cluster's total
 * weight (sum of input weights). The cluster that absorbed the most
 * pixels comes out heaviest, irrespective of merge order.
 *
 * Complexity is O(N² log N) due to repeated nearest-pair scans;
 * intended for ≤ a few hundred input bins (i.e., post-histogram).
 * Calling against raw pixel arrays will be slow; feed it the output
 * of `gallery:histogram` instead.
 */
class ClusterDeltaEMerge {
  readonly 'name' = 'clusterDeltaEMerge';

  apply(colors: readonly ColorRecordInterfaceType[], k: number): ColorRecordInterfaceType[] {
    if (colors.length === 0) {return [];}
    if (k < 1) {
      throw ValidationError.create({
        'message': 'ClusterDeltaEMerge.apply: k must be a positive number',
        'path':    'k',
        'violations': [{
          'details': { 'expected': 'k >= 1', 'received': k },
          'message': 'k is not a positive number',
          'path':    'k'
        }]
      });
    }
    const targetK = Math.min(Math.floor(k), colors.length);
    if (targetK >= colors.length) {
      /* Pass-through: no clustering needed. Return inputs verbatim when
         a weight is already declared (preserves `displayP3` + every hint
         the upstream task attached); otherwise reallocate via the factory
         (the only sanctioned allocation point; spread-append would
         break the monomorphic hidden class per ColorRecordInterfaceType
         docs) while merging existing hint keys (`role`, `intent`, etc.)
         with the stamped `weight: 1`. */
      return colors.map((c) => {
        if (typeof c.hints?.weight === 'number' && c.hints.weight > 0) {return c;}
        const hints = { ...(c.hints ?? {}), 'weight': 1 };
        return colorRecordFactory.fromOklch(c.oklch.l, c.oklch.c, c.oklch.h, { 'alpha': c.alpha, 'hints': hints, 'sourceFormat': c.sourceFormat });
      });
    }

    let clusters: ClusterInterface[] = colors.map((c) => {return {
      'centroid': c,
      'weight':   recordWeight(c)
    };});

    while (clusters.length > targetK) {
      let bestI = 0;
      let bestJ = 1;
      let bestD = Infinity;
      for (let i = 0; i < clusters.length; i++) {
        const a = clusters[i];
        if (a === undefined) {continue;}
        for (let j = i + 1; j < clusters.length; j++) {
          const b = clusters[j];
          if (b === undefined) {continue;}
          // Non-finite distances (NaN from a degenerate centroid, e.g.
          // zero-chroma both sides where the deltaE branch divides by
          // C1p*C2p === 0) would silently skip the pair otherwise and,
          // if EVERY pair returns NaN, the nearest-pair scan never picks
          // a winner and the loop spins forever. Coerce non-finite to
          // Infinity so the comparison is total, and the fallback below
          // guarantees forward progress when all pairs tie.
          const raw = deltaE2000.apply(a.centroid, b.centroid);
          const d   = Number.isFinite(raw) ? raw : Infinity;
          if (d < bestD) {
            bestD = d;
            bestI = i;
            bestJ = j;
          }
        }
      }
      // Forward-progress guarantee: if every pair scanned to Infinity
      // (a pathological all-NaN centroid set), still merge the first
      // two clusters so we drain toward targetK rather than hang.
      if (bestD === Infinity) {
        bestI = 0;
        bestJ = 1;
      }
      const a = clusters[bestI];
      const b = clusters[bestJ];
      if (a === undefined || b === undefined) {break;}
      const merged = Centroids.merge(a, b);
      clusters = [
        ...clusters.slice(0, bestI),
        merged,
        ...clusters.slice(bestI + 1, bestJ),
        ...clusters.slice(bestJ + 1)
      ];
    }

    return clusters.map((cl) => { const result = cl.centroid; return result; });
  }
}

/** Singleton instance registered as the `clusterDeltaEMerge` math primitive. */
export const clusterDeltaEMerge = new ClusterDeltaEMerge();
import { ValidationError } from '@studnicky/errors';

import type { ColorRecordInterfaceType } from '../types/index.ts';

import { colorRecordFactory } from './ColorRecordFactory.ts';

type BucketInterface = {
  'colors': ColorRecordInterfaceType[];
};

function bucketMedian(bucket: BucketInterface): ColorRecordInterfaceType {
  const n = bucket.colors.length;
  if (n === 0) {
    return colorRecordFactory.fromOklch(0.5, 0, 0);
  }
  let sumAlpha = 0; let sumC = 0; let sumH = 0; let sumL = 0;
  for (let i = 0; i < n; i++) {
    const col = bucket.colors[i];
    if (col === undefined) {continue;}
    sumL += col.oklch.l;
    sumC += col.oklch.c;
    sumH += col.oklch.h;
    sumAlpha += col.alpha;
  }
  return colorRecordFactory.fromOklch(sumL / n, sumC / n, sumH / n, { 'alpha': sumAlpha / n });
}

function rangeOf(colors: ColorRecordInterfaceType[], channel: 'l' | 'c' | 'h'): number {
  if (colors.length === 0) {return 0;}
  let max = -Infinity; let min = Infinity;
  for (let i = 0; i < colors.length; i++) {
    const v = colors[i]?.oklch[channel] ?? 0;
    if (v < min) {min = v;}
    if (v > max) {max = v;}
  }
  return max - min;
}

class Bucket {
  static split(bucket: BucketInterface): [BucketInterface, BucketInterface] {
    const colors = bucket.colors;
    const lRange = rangeOf(colors, 'l');
    const cRange = rangeOf(colors, 'c');
    const hRange = rangeOf(colors, 'h') / 360;

    let channel: 'l' | 'c' | 'h' = 'l';
    if (cRange > lRange && cRange > hRange) {channel = 'c';}
    else if (hRange > lRange) {channel = 'h';}

    const sorted = [...colors].sort((a, b) => {return a.oklch[channel] - b.oklch[channel];});
    const mid = Math.floor(sorted.length / 2);

    return [
      { 'colors': sorted.slice(0, mid) },
      { 'colors': sorted.slice(mid) }
    ];
  }
}

class ClusterMedianCut {
  readonly 'name' = 'clusterMedianCut';

  apply(colors: readonly ColorRecordInterfaceType[], k: number): ColorRecordInterfaceType[] {
    if (colors.length === 0) {return [];}
    if (k < 1) {
      throw ValidationError.create({
        'message': 'ClusterMedianCut.apply: k must be a positive number',
        'path':    'k',
        'violations': [{
          'details': { 'expected': 'k >= 1', 'received': k },
          'message': 'k is not a positive number',
          'path':    'k'
        }]
      });
    }

    const targetK = Math.min(Math.floor(k), colors.length);
    let buckets: BucketInterface[] = [{ 'colors': [...colors] }];

    while (buckets.length < targetK) {
      let maxSize = 0;
      let maxIdx = 0;
      for (let i = 0; i < buckets.length; i++) {
        const len = buckets[i]?.colors.length ?? 0;
        if (len > maxSize) {
          maxSize = len;
          maxIdx = i;
        }
      }
      const target = buckets[maxIdx];
      if (target === undefined || target.colors.length <= 1) {break;}

      const [left, right] = Bucket.split(target);
      buckets = [
        ...buckets.slice(0, maxIdx),
        left,
        right,
        ...buckets.slice(maxIdx + 1)
      ];
    }

    return buckets.map(bucketMedian);
  }
}

/** Singleton instance registered as the `clusterMedianCut` math primitive. */
export const clusterMedianCut = new ClusterMedianCut();
import { ValidationError } from '@studnicky/errors';

import type { ColorRecordInterfaceType } from '../types/index.ts';

import { colorRecordFactory } from './ColorRecordFactory.ts';

type BucketInterface = {
  'colors': ColorRecordInterfaceType[];
  'totalWeight': number;
};

function recordWeight(record: ColorRecordInterfaceType): number {
  const w = record.hints?.weight;
  return typeof w === 'number' && w > 0 ? w : 1;
}

function bucketCentroid(bucket: BucketInterface): ColorRecordInterfaceType {
  const colors = bucket.colors;
  const n = colors.length;
  if (n === 0) {
    return colorRecordFactory.fromOklch(0.5, 0, 0);
  }
  let sumA = 0; let sumAlpha = 0; let sumB = 0; let sumL = 0; let sumW = 0;
  for (let i = 0; i < n; i++) {
    const col = colors[i];
    if (col === undefined) {continue;}
    const w = recordWeight(col);
    const hRad = (col.oklch.h * Math.PI) / 180;
    sumL     += col.oklch.l * w;
    sumA     += col.oklch.c * Math.cos(hRad) * w;
    sumB     += col.oklch.c * Math.sin(hRad) * w;
    sumAlpha += col.alpha   * w;
    sumW     += w;
  }
  if (sumW === 0) {
    return colorRecordFactory.fromOklch(0.5, 0, 0);
  }
  const L = sumL / sumW;
  const aMean = sumA / sumW;
  const bMean = sumB / sumW;
  const C = Math.sqrt(aMean * aMean + bMean * bMean);
  let H = (Math.atan2(bMean, aMean) * 180) / Math.PI;
  if (H < 0) {H += 360;}
  return colorRecordFactory.fromOklch(L, C, H, { 'alpha': sumAlpha / sumW, 'hints': { 'weight': sumW }, 'sourceFormat': 'oklch' });
}

function rangeOf(colors: ColorRecordInterfaceType[], channel: 'l' | 'c' | 'h'): number {
  if (colors.length === 0) {return 0;}
  let max = -Infinity; let min = Infinity;
  for (let i = 0; i < colors.length; i++) {
    const v = colors[i]?.oklch[channel] ?? 0;
    if (v < min) {min = v;}
    if (v > max) {max = v;}
  }
  return max - min;
}

class Bucket {
  static split(bucket: BucketInterface): [BucketInterface, BucketInterface] {
    const colors = bucket.colors;
    const lRange = rangeOf(colors, 'l');
    const cRange = rangeOf(colors, 'c');
    const hRange = rangeOf(colors, 'h') / 360;

    let channel: 'l' | 'c' | 'h' = 'l';
    if (cRange > lRange && cRange > hRange) {channel = 'c';}
    else if (hRange > lRange) {channel = 'h';}

    const sorted = [...colors].sort((a, b) => {return a.oklch[channel] - b.oklch[channel];});

    const half = bucket.totalWeight / 2;
    let acc = 0;
    let splitIdx = 0;
    for (let i = 0; i < sorted.length; i++) {
      const col = sorted[i];
      if (col === undefined) {continue;}
      acc += recordWeight(col);
      if (acc >= half) {
        splitIdx = i + 1;
        break;
      }
    }
    if (splitIdx <= 0)              {splitIdx = 1;}
    if (splitIdx >= sorted.length)  {splitIdx = sorted.length - 1;}

    const left  = sorted.slice(0, splitIdx);
    const right = sorted.slice(splitIdx);
    let lw = 0;
    for (const col of left)  {lw += recordWeight(col);}
    let rw = 0;
    for (const col of right) {rw += recordWeight(col);}
    return [
      { 'colors': left,  'totalWeight': lw },
      { 'colors': right, 'totalWeight': rw }
    ];
  }
}

/**
 * Weighted median-cut clustering. Generalises {@link import('./ClusterMedianCut.ts').ClusterMedianCut}
 * to respect per-record `hints.weight`. Bucket splits choose the channel
 * with the widest range and partition by CUMULATIVE WEIGHT (not count),
 * so a heavily-weighted color survives reduction even when surrounded
 * by many low-weight neighbours.
 *
 * Output records carry `hints.weight` set to the cluster's total
 * weight, so downstream tasks (spectrograph, role assignment) can
 * paint cluster importance proportional to the source's pixel density.
 *
 * Selecting the largest bucket to split:
 *   the bucket with the HIGHEST totalWeight is split next. This biases
 *   the reduction toward separating dense regions of color space
 *   rather than thinly-populated outliers.
 */
class ClusterMedianCutWeighted {
  readonly 'name' = 'clusterMedianCutWeighted';

  apply(colors: readonly ColorRecordInterfaceType[], k: number): ColorRecordInterfaceType[] {
    if (colors.length === 0) {return [];}
    if (k < 1) {
      throw ValidationError.create({
        'message': 'ClusterMedianCutWeighted.apply: k must be a positive number',
        'path':    'k',
        'violations': [{
          'details': { 'expected': 'k >= 1', 'received': k },
          'message': 'k is not a positive number',
          'path':    'k'
        }]
      });
    }

    const targetK = Math.min(Math.floor(k), colors.length);
    let totalW = 0;
    for (const col of colors) {totalW += recordWeight(col);}
    let buckets: BucketInterface[] = [{ 'colors': [...colors], 'totalWeight': totalW }];

    while (buckets.length < targetK) {
      let bestScore = -1;
      let bestIdx = 0;
      for (let i = 0; i < buckets.length; i++) {
        const bucket = buckets[i];
        if (bucket === undefined || bucket.colors.length <= 1) {continue;}
        // Bucket-selection score: weight × widest_range.
        //
        // Selecting purely by weight makes a huge uniform region (page
        // whites, sky) hog every split, so smaller-but-distinct hues
        // never get their own cluster; the resulting palette ends up
        // as N shades of the same neutral. Selecting purely by range
        // (Heckbert's original) ignores pixel density and lets a tiny
        // outlier dominate.
        //
        // weight × range is the standard minimum-within-cluster-error
        // heuristic: it picks the bucket where refining the partition
        // reduces clustering error the most. Hue is normalised to
        // [0, 1] by dividing by 360 so the three channels compare
        // fairly.
        const lRange = rangeOf(bucket.colors, 'l');
        const cRange = rangeOf(bucket.colors, 'c');
        const hRange = rangeOf(bucket.colors, 'h') / 360;
        const widestRange = Math.max(lRange, cRange, hRange);
        const score = bucket.totalWeight * widestRange;
        if (score > bestScore) {
          bestScore = score;
          bestIdx = i;
        }
      }
      const target = buckets[bestIdx];
      if (target === undefined || target.colors.length <= 1) {break;}

      const [left, right] = Bucket.split(target);
      buckets = [
        ...buckets.slice(0, bestIdx),
        left,
        right,
        ...buckets.slice(bestIdx + 1)
      ];
    }

    return buckets.map(bucketCentroid);
  }
}

