    const { h, l, s } = raw;
    const a = typeof raw.a === 'number' ? raw.a : 1;
    const alpha = a > 1 ? a / 100 : a;
    const sat = s > 1 ? s / 100 : s;
    const lig = l > 1 ? l / 100 : l;

    return colorRecordFactory.fromHsl(h, sat, lig, { 'alpha': clamp01.apply(alpha), 'sourceFormat': 'hsl' });
