      'message': 'intake:imagePixels — image has no non-transparent pixels',
      'path':    'raw',
      'violations': [{
        'details': { 'height': raw.height, 'pixelCount': pixelCount, 'width': raw.width },
        'message': 'every pixel in the image has alpha 0',
        'path':    'raw'
