/**
 * Matches CSS Color 4 `color(display-p3 r g b)` and
 * `color(display-p3 r g b / alpha)` syntax. Channel values are 0..1
 * floats. Alpha is optional. Whitespace tolerant.
 *
 * Captures: `[1] r`, `[2] g`, `[3] b`, `[4] alpha?` (the slash-prefixed group).
 */
const P3_PATTERN = /^color\(\s*display-p3\s+(-?\d*\.?\d+)\s+(-?\d*\.?\d+)\s+(-?\d*\.?\d+)(?:\s*\/\s*(-?\d*\.?\d+))?\s*\)$/i;

/**
 * Intake task that parses CSS Color 4 `color(display-p3 r g b [/alpha])`
 * strings into {@link ColorRecordInterfaceType} entries with `displayP3`
 * populated directly from the input and `rgb` gamut-mapped down to sRGB
 * so sRGB-only consumers stay safe.
 *
 * Conversion chain (CSS Color 4 §17.6 sample code):
 *   1. Parse the string (P3 channels in `[0, 1]`).
 *   2. Display-P3 gamma → linear Display-P3 (inverse sRGB-style gamma).
 *   3. Linear Display-P3 → linear sRGB via the matrix inverse of the
 *      `linearSrgb → linearP3` chain used in
 *      {@link import('../../math/OklchToDisplayP3.ts').OklchToDisplayP3}.
 *   4. Linear sRGB → OKLab (Björn Ottosson matrices) → OKLCH.
 *   5. If any linear-sRGB channel is outside `[0, 1]`, gamut-map the
 *      derived OKLCH back into sRGB (chroma-reduction along L+H).
 *
 * The resulting record stores:
 *   - `displayP3`: the input (r, g, b), preserved verbatim (clamped to [0,1]).
 *   - `rgb`/`hex`: the gamut-mapped sRGB representation.
 *   - `oklch`:     derived from the original wide-gamut point.
 *   - `sourceFormat: 'displayP3'`.
 */
class IntakeP3 implements TaskInterface {
  readonly 'name' = 'intake:p3';

  readonly 'manifest': TaskManifestInterfaceType = {
    'description': 'Parses CSS color(display-p3 r g b [/ alpha]) strings into ColorRecord entries with displayP3 populated.',
    'name':        'intake:p3',
    'reads':       ['input.colors'],
    'writes':      ['colors']
  };

  /**
   * Parses a single value as a CSS `color(display-p3 …)` string. Throws when
   * the input is not a string or does not match the Display-P3 pattern.
   * Used by IntakeAny for format dispatch (via try/catch).
   */
  parse(raw: unknown): ColorRecordInterfaceType {
    if (typeof raw !== 'string') {
      throw ValidationError.create({
        'message': 'intake:p3 — expected a string input',
        'path':    'raw',
        'violations': [{
          'details': { 'expectedType': 'string', 'receivedType': typeof raw },
          'message': 'input is not a string',
          'path':    'raw'
        }]
      });
    }
    const match = P3_PATTERN.exec(raw.trim());
    if (match === null) {
      throw ValidationError.create({
        'message': 'intake:p3 — not a display-p3 string',
        'path':    'raw',
        'violations': [{
          'details': { 'expectedFormat': 'color(display-p3 r g b [/ alpha])', 'received': raw },
          'message': 'value does not match the display-p3 CSS syntax',
          'path':    'raw'
        }]
      });
    }

    const p3R   = parseFloat(match[1]!);
    const p3G   = parseFloat(match[2]!);
    const p3B   = parseFloat(match[3]!);
    const alpha = match[4] !== undefined ? parseFloat(match[4]) : 1;

    return recordFromP3(p3R, p3G, p3B, alpha, undefined);
  }

  /**
   * Parses a single entry, rethrowing with index/context on failure.
   * Extracted from {@link IntakeP3.run} so the loop body contains only
   * a function call, not a try-catch, per V8 optimization guidance.
   */
  private parseEntry(raw: unknown, index: number): ColorRecordInterfaceType {
    try {
      return this.parse(raw);
    } catch {
      throw ValidationError.create({
        'message': `intake:p3 — entry at index ${index} is not a Display-P3 string`,
        'path':    `input.colors[${index}]`,
        'violations': [{
          'details': {
            'expectedFormat': 'color(display-p3 r g b [/ alpha])',
            'index':          index,
            'received':       JSON.stringify(raw) ?? 'undefined'
          },
          'message': 'entry does not match the display-p3 CSS syntax',
          'path':    `input.colors[${index}]`
        }]
      });
    }
  }

  run(state: PaletteStateInterface, ctx: PipelineContextInterface): void {
    for (let i = 0; i < state.input.colors.length; i++) {
      const raw = state.input.colors[i];
      const record = this.parseEntry(raw, i);
      state.colors.push(record);
      ctx.logger.debug(
        LogBody.create()
          .component('IntakeP3')
          .operation('run')
          .status(LOG_STATUS.SUCCESS)
          .message('Parsed display-p3 value')
          .context({
            'hex': record.hex,
            'raw': raw
          })
          .build()
      );
    }
  }
}

/** Singleton instance registered as the `intake:p3` pipeline task. */
export const intakeP3 = new IntakeP3();

/**
 * Internal: build a record from raw P3 channel floats. Extracted from
 * the task so future intake variants (e.g. an object literal form
 * `{ p3: [r, g, b] }`) can reuse the conversion path without
 * re-implementing the matrix chain.
 */
function recordFromP3(
  p3R:   number,
  p3G:   number,
  p3B:   number,
  alpha: number,
  hints: ColorHintsInterfaceType | undefined
): ColorRecordInterfaceType {
  // 1. Display-P3 gamma → linear Display-P3 (sign-preserving for
  //    out-of-range floats; spec guarantees inputs in [0, 1] but be
  //    tolerant of slightly-out-of-range floats).
  const lp3R = P3.decode(p3R);
  const lp3G = P3.decode(p3G);
  const lp3B = P3.decode(p3B);

  // 2. Linear Display-P3 → linear sRGB. Matrix is the inverse of the
  //    composed `linearSrgb → XYZ-D65 → linearP3` chain. Source: CSS
  //    Color 4 §17.6 sample code.
  const lsR =  1.2249401  * lp3R - 0.2249404  * lp3G + 0.0000000  * lp3B;
  const lsG = -0.0420569  * lp3R + 1.0420571  * lp3G - 0.0000001  * lp3B;
  const lsB = -0.0196376  * lp3R - 0.0786361  * lp3G + 1.0982735  * lp3B;

  // 3. Linear sRGB → OKLab → OKLCH (Björn Ottosson). Computed BEFORE
  //    gamma-encoding sRGB so the precision survives super-saturated
  //    inputs.
  const oklch = linearSrgbToOklch(lsR, lsG, lsB);

  // 4. Determine whether the linear sRGB is in-gamut. If yes, emit
  //    directly. If no, gamut-map the OKLCH back into sRGB and use
  //    that for the sRGB-safe `rgb`/`hex`.
  const inSrgb =
    lsR >= 0 && lsR <= 1 &&
    lsG >= 0 && lsG <= 1 &&
    lsB >= 0 && lsB <= 1;

  let safeRgb: RgbInterfaceType;
  if (inSrgb) {
    const encoded = linearToSrgb.apply(lsR, lsG, lsB);
    safeRgb = {
      'b': clamp01.apply(encoded.b),
      'g': clamp01.apply(encoded.g),
      'r': clamp01.apply(encoded.r)
    };
  } else {
    const mapped     = gamutMapSrgb.apply(oklch.l, oklch.c, oklch.h);
    const mappedLin  = oklchToLinearSrgb(mapped.l, mapped.c, mapped.h);
    const mappedSrgb = linearToSrgb.apply(mappedLin.r, mappedLin.g, mappedLin.b);
    safeRgb = {
      'b': clamp01.apply(mappedSrgb.b),
      'g': clamp01.apply(mappedSrgb.g),
      'r': clamp01.apply(mappedSrgb.r)
    };
  }

  return {
    'alpha':        clamp01.apply(alpha),
    'displayP3':    {
      'b': clamp01.apply(p3B),
      'g': clamp01.apply(p3G),
      'r': clamp01.apply(p3R)
    },
    'hex':          rgbToHex.apply(safeRgb.r, safeRgb.g, safeRgb.b),
    'hints':        hints,
    'oklch':        oklch,
    'rgb':          safeRgb,
    'sourceFormat': 'displayP3'
  };
}

/** Display-P3 inverse gamma (same curve as sRGB; sign-preserving). */
class P3 {
  static decode(v: number): number {
    const sign = v < 0 ? -1 : 1;
    const abs  = Math.abs(v);
    if (abs <= 0.04045) {
      return sign * (abs / 12.92);
    }
    return sign * Math.pow((abs + 0.055) / 1.055, 2.4);
  }
}

/**
 * Linear sRGB → OKLCH. Splits {@link import('../../math/ColorRecordFactory.ts')}
 * `rgbToOklchRaw` so we can skip the gamma-decode step (input is already
 * linear) and avoid clamping for out-of-gamut inputs. Same Björn
 * Ottosson matrices.
 */
function linearSrgbToOklch(rl: number, gl: number, bl: number): OklchInterfaceType {
  let x = 0.4122214708 * rl + 0.5363325363 * gl + 0.0514459929 * bl;
  let y = 0.2119034982 * rl + 0.6806995451 * gl + 0.1073969566 * bl;
  let z = 0.0883024619 * rl + 0.2817188376 * gl + 0.6299787005 * bl;

  // Sign-preserving cube root so negative LMS values from out-of-gamut
  // inputs still produce a sane OKLab triple.
  x = signCbrt(x);
  y = signCbrt(y);
  z = signCbrt(z);

  const labL = 0.2104542553 * x + 0.7936177850 * y - 0.0040720468 * z;
  const labA = 1.9779984951 * x - 2.4285922050 * y + 0.4505937099 * z;
  const labB = 0.0259040371 * x + 0.7827717662 * y - 0.8086757660 * z;

  const c = Math.sqrt(labA * labA + labB * labB);
  let h = (Math.atan2(labB, labA) * 180) / Math.PI;
  if (h < 0) {
    h += 360;
  }

  return {
    'c': clamp.apply(0, 0.5, c),
    'h': h % 360,
    'l': clamp01.apply(labL)
  };
}

function signCbrt(v: number): number {
  if (v < 0) {return -Math.cbrt(-v);}
  return Math.cbrt(v);
}

/** OKLCH → linear sRGB (Björn Ottosson). Local helper; mirrors the
 *  matrix used in OklchToRgbRaw/OklchToDisplayP3. */
function oklchToLinearSrgb(l: number, c: number, h: number): RgbInterfaceType {
  const hRad = (h * Math.PI) / 180;
  const a = c * Math.cos(hRad);
  const b = c * Math.sin(hRad);

  let x = l + 0.3963377774 * a + 0.2158037573 * b;
  let y = l - 0.1055613458 * a - 0.0638541728 * b;
  let z = l - 0.0894841775 * a - 1.291485548  * b;

  x = x * x * x;
  y = y * y * y;
  z = z * z * z;

  return {
    'b': -0.0041960863 * x - 0.7034186147 * y + 1.707614701  * z,
    'g': -1.2684380046 * x + 2.6097574011 * y - 0.3413193965 * z,
    'r': +4.0767416621 * x - 3.3077115913 * y + 0.2309699292 * z
  };
}
import { ValidationError } from '@studnicky/errors';
import { LogBody } from '@studnicky/logger/builders';
import { LOG_STATUS } from '@studnicky/logger/constants';

import type {
  ColorRecordInterfaceType,
  PaletteStateInterface,
  PipelineContextInterface,
  RgbInterfaceType,
  TaskInterface,
  TaskManifestInterfaceType
} from '../../types/index.ts';

import { colorRecordFactory } from '../../math/ColorRecordFactory.ts';

type RgbInput = RgbInterfaceType & {
  'a'?: number;
};

function isRgbInput(v: unknown): v is RgbInput {
  if (typeof v !== 'object' || v === null) {return false;}
  const o = v as Record<string, unknown>;
  return typeof o.r === 'number'
    && typeof o.g === 'number'
    && typeof o.b === 'number';
}

/**
 * Intake task that converts `{r, g, b, a?}` objects into `ColorRecord`s.
 * Auto-detects whether components are 0..1 or 0..255 by checking the
 * maximum value, so callers can pass either CSS-style bytes or float
 * literals without flagging the unit. Entries that carry `h`, `l`, or
 * `c` keys are not RGB objects and cause a throw when used with the
 * strict `intake:rgb` task. Use `intake:any` for tolerant dispatch.
 */
class IntakeRgb implements TaskInterface {
  readonly 'name' = 'intake:rgb';

  readonly 'manifest': TaskManifestInterfaceType = {
    'description': 'Parses {r,g,b,a?} in 0..1 or 0..255 (auto-detected by max value) into ColorRecord entries. Throws on non-RGB input.',
    'name':        'intake:rgb',
    'reads':       ['input.colors'],
    'writes':      ['colors']
  };

  /**
   * Parses a single value as an RGB object. Throws when the input is not a
   * valid `{r,g,b}` object or carries keys from a different format (h/l/c).
   * Used by IntakeAny for format dispatch (via try/catch).
   */
  parse(raw: unknown): ColorRecordInterfaceType {
    if (!isRgbInput(raw)) {
      throw ValidationError.create({
        'message': 'intake:rgb — expected an {r,g,b} object',
        'path':    'raw',
        'violations': [{
          'details': { 'expectedShape': '{r: number, g: number, b: number, a?: number}', 'receivedType': typeof raw },
          'message': 'input is not an RGB object',
          'path':    'raw'
        }]
      });
    }
    const o = raw as unknown as Record<string, unknown>;
    if (typeof o.h === 'number' || typeof o.l === 'number' || typeof o.c === 'number') {
      throw ValidationError.create({
        'message': 'intake:rgb — object has conflicting format keys',
        'path':    'raw',
        'violations': [{
          'details': { 'conflictingKeys': ['h', 'l', 'c'], 'reason': 'h/l/c indicate a different format (hsl/oklch/lab)' },
          'message': 'object carries keys from a different color format',
          'path':    'raw'
        }]
      });
    }

    let { b, g, r } = raw;
    const a = typeof raw.a === 'number' ? raw.a : 1;

    if (r > 1 || g > 1 || b > 1) {
      r = r / 255;
      g = g / 255;
      b = b / 255;
    }

    const alpha = a > 1 ? a / 255 : a;
    return colorRecordFactory.fromRgb(r, g, b, { 'alpha': alpha });
  }

  /**
   * Wraps {@link IntakeRgb.parse} so the dispatch loop in
   * {@link IntakeRgb.run} does not carry a try/catch in its body (V8
   * de-optimises try/catch inside hot loops).
   */
  #tryParse(raw: unknown): ColorRecordInterfaceType | undefined {
    try {
      return this.parse(raw);
    } catch {
      return undefined;
    }
  }

  run(state: PaletteStateInterface, ctx: PipelineContextInterface): void {
    for (let i = 0; i < state.input.colors.length; i++) {
      const raw = state.input.colors[i];
      const record = this.#tryParse(raw);
      if (record === undefined) {
        throw ValidationError.create({
          'message': `intake:rgb — entry at index ${i} is not an RGB object`,
          'path':    `input.colors[${i}]`,
          'violations': [{
            'details': {
              'expectedShape': '{r: 0..1 or 0..255, g: 0..1 or 0..255, b: 0..1 or 0..255, a?: number}',
              'index':         i,
              'received':      JSON.stringify(raw) ?? 'undefined'
            },
            'message': 'entry does not match the RGB object shape',
            'path':    `input.colors[${i}]`
          }]
        });
      }
      state.colors.push(record);
      ctx.logger.debug(
        LogBody.create()
          .component('IntakeRgb')
          .operation('run')
          .status(LOG_STATUS.SUCCESS)
          .message('Parsed rgb value')
          .context({ 'b': record.rgb.b, 'g': record.rgb.g, 'hex': record.hex, 'r': record.rgb.r })
          .build()
      );
    }
  }
}

/** Singleton instance registered as the `intake:rgb` pipeline task. */
export const intakeRgb = new IntakeRgb();
import { ValidationError } from '@studnicky/errors';
import { LogBody } from '@studnicky/logger/builders';
import { LOG_STATUS } from '@studnicky/logger/constants';

import type {
  PaletteStateInterface,
  PipelineContextInterface,
  TaskInterface,
  TaskManifestInterfaceType
} from '../../types/index.ts';

import { intakeHex }                              from './IntakeHex.ts';
import { intakeHsl }                              from './IntakeHsl.ts';
import { intakeImagePixels }                      from './IntakeImagePixels.ts';
import { intakeLab }                              from './IntakeLab.ts';
import { intakeNamed }                            from './IntakeNamed.ts';
import { intakeOklch }                            from './IntakeOklch.ts';
import { intakeP3 }                               from './IntakeP3.ts';
import { intakeRgb }                              from './IntakeRgb.ts';
import { isImagePixelInput }                      from './IsImagePixelInput.ts';

/**
 * Non-image delegates tried in order for every scalar entry.
 * Hex runs before Named so that any-cased three-hex-char strings like
 * `"f0f"` resolve as hex, not as a named color miss.
 */
const SCALAR_DELEGATES = [
  intakeHex,
  intakeP3,
  intakeRgb,
  intakeHsl,
  intakeOklch,
  intakeLab,
  intakeNamed
] as const;

/**
 * Attempts a single delegate's `parse` against `raw`, swallowing a parse
 * failure into `undefined`. Extracted to a wrapper so the dispatch loop in
 * {@link IntakeAny.run} does not carry a try/catch in its body (V8
 * de-optimises try/catch inside hot loops).
 */
function tryParse(
  delegate: (typeof SCALAR_DELEGATES)[number],
  raw: unknown
): ReturnType<(typeof SCALAR_DELEGATES)[number]['parse']> | undefined {
  try {
    return delegate.parse(raw);
  } catch {
    return undefined;
  }
}

/**
 * The default intake task. Iterates `state.input.colors` per entry and
 * tries each format-specific delegate's `parse` in order via try/catch.
 * The first delegate whose `parse` succeeds wins and the result is pushed.
 * ImageData entries are dispatched to `IntakeImagePixels.pushAllPixels`
 * which pushes one record per non-transparent pixel.
 *
 * If NO delegate matches a given entry, IntakeAny throws — truly
 * malformed input is an error, not a silent no-op. Use typed intakes
 * (`intake:hex` etc.) for strict single-format enforcement.
 *
 * Order matters for ambiguous strings: IntakeHex is tried before
 * IntakeNamed so hex strings are not mistaken for named colors.
 */
class IntakeAny implements TaskInterface {
  readonly 'name' = 'intake:any';

  readonly 'manifest': TaskManifestInterfaceType = {
    'description': 'Recommended default intake task. Dispatches each entry to the first matching format delegate. Throws if no delegate matches.',
    'name':        'intake:any',
    'reads':       ['input.colors'],
    'writes':      ['colors']
  };

  run(state: PaletteStateInterface, ctx: PipelineContextInterface): void {
    for (let i = 0; i < state.input.colors.length; i++) {
      const raw = state.input.colors[i];

      // ImageData entries produce N records (one per pixel). Handle first.
      if (isImagePixelInput(raw)) {
        intakeImagePixels.pushAllPixels(raw, state, ctx);
        continue;
      }

      // Scalar entries: try each delegate until one parse() succeeds.
      let matched = false;
      for (const delegate of SCALAR_DELEGATES) {
        const record = tryParse(delegate, raw);
        if (record === undefined) {
          // format mismatch — try next delegate
          continue;
        }
        state.colors.push(record);
        matched = true;
        ctx.logger.debug(
          LogBody.create()
            .component('IntakeAny')
            .operation('run')
            .status(LOG_STATUS.SUCCESS)
            .message('Dispatched entry')
            .context({
              'delegate': delegate.name,
              'hex':      record.hex,
              'index':    i
            })
            .build()
        );
        break;
      }

      if (!matched) {
        throw ValidationError.create({
          'message': `intake:any — entry at index ${i} does not match any known color format`,
          'path':    `input.colors[${i}]`,
          'violations': [{
            'details': {
              'acceptedFormats': [
                'hex (#RGB, #RRGGBB)',
                'display-p3',
                '{r,g,b}',
                '{h,s,l}',
                '{l,c,h} (oklch)',
                '{l,a,b} (lab)',
                'CSS named color',
                'ImageData'
              ],
              'index':    i,
              'received': JSON.stringify(raw) ?? 'undefined'
            },
            'message': 'entry does not match any known color format',
            'path':    `input.colors[${i}]`
          }]
        });
      }
    }

    ctx.logger.debug(
      LogBody.create()
        .component('IntakeAny')
        .operation('run')
        .status(LOG_STATUS.SUCCESS)
        .message('Total colors after intake')
        .context({ 'count': state.colors.length })
        .build()
    );
  }
}

/** Singleton instance registered as the `intake:any` pipeline task. */
export const intakeAny = new IntakeAny();
import { LogBody } from '@studnicky/logger/builders';
import { LOG_STATUS } from '@studnicky/logger/constants';

import type {
  ColorHintsInterfaceType,
  ColorRecordInterfaceType,
  PaletteStateInterface,
  PipelineContextInterface,
  RoleDefinitionInterfaceType,
  TaskInterface,
  TaskManifestInterfaceType
} from '../../types/index.ts';

import { colorRecordFactory } from '../../math/ColorRecordFactory.ts';

/**
 * Rotate `src` toward `target` along the shortest arc, by at most `maxDeg`
 * degrees. A bounded nudge: keeps the resolved hue rooted in the palette while
 * leaning it toward a semantic target.
 */
function hueTowards(src: number, target: number, maxDeg: number): number {
  const delta = ((target - src + 540) % 360) - 180;
  const clamped = Math.max(-maxDeg, Math.min(maxDeg, delta));
  return (((src + clamped) % 360) + 360) % 360;
}

/**
 * Resolves the target hue for a candidate being nudged into a role:
 * an absolute/clamped `hue` target wins when set, otherwise `hueOffset`
 * is used as-is, otherwise the candidate's own hue is left unchanged.
 */
class TargetHue {
  static resolve(h: number, role: RoleDefinitionInterfaceType): number {
    if (role.hue !== undefined) {
      return role.hueClamp !== undefined
        ? hueTowards(h, role.hue, role.hueClamp)
        : (((role.hue % 360) + 360) % 360);
    }
    return role.hueOffset ?? h;
  }
}

function rangeCenter(range: readonly [number, number]): number {
  return (range[0] + range[1]) / 2;
}

function clampToRange(value: number, range: readonly [number, number]): number {
  if (value < range[0]) {return range[0];}
  if (value > range[1]) {return range[1];}
  return value;
}

function distanceToRoleCenter(color: ColorRecordInterfaceType, role: RoleDefinitionInterfaceType): number {
  const { c, h, l } = color.oklch;
  let distance = 0;

  if (role.lightnessRange !== undefined) {
    const target = rangeCenter(role.lightnessRange);
    distance += Math.abs(l - target) * 2;
  }

  if (role.chromaRange !== undefined) {
    const target = rangeCenter(role.chromaRange);
    distance += Math.abs(c - target);
  }

  if (role.hueOffset !== undefined) {
    const hueDiff = Math.abs(((h - role.hueOffset + 540) % 360) - 180);
    distance += (hueDiff / 360) * 0.5;
  }

  return distance;
}

/**
 * Adjusts a candidate color's OKLCH so it satisfies the role's
 * lightnessRange, chromaRange, and (if specified) absolute hueOffset
 * target. Already-conformant candidates are returned unchanged so the
 * common case is allocation-free, unless the role declares an `intent`
 * that the candidate's hints lack, in which case a new record is
 * allocated through the factory so `hints.intent` is propagated onto
 * the resolved record (the schema's intent is authoritative; see the
 * JSDoc on {@link RoleDefinitionInterfaceType.intent}).
 */
function nudgeIntoRole(
  candidate: ColorRecordInterfaceType,
  role: RoleDefinitionInterfaceType
): ColorRecordInterfaceType {
  const { c, h, l } = candidate.oklch;

  const targetL = role.lightnessRange !== undefined ? clampToRange(l, role.lightnessRange) : l;
  const targetC = role.chromaRange    !== undefined ? clampToRange(c, role.chromaRange)    : c;
  const targetH = TargetHue.resolve(h, role);

  const needsRangeNudge = targetL !== l || targetC !== c || targetH !== h;
  const needsIntent     = role.intent !== undefined && candidate.hints?.intent !== role.intent;

  if (!needsRangeNudge && !needsIntent) {
    return candidate;
  }

  const nextHints: ColorHintsInterfaceType | undefined = role.intent !== undefined
    ? { ...candidate.hints, 'intent': role.intent }
    : candidate.hints;

  return colorRecordFactory.fromOklch(
    targetL,
    targetC,
    targetH,
    { 'alpha': candidate.alpha, 'hints': nextHints, 'sourceFormat': candidate.sourceFormat }
  );
}

function synthesizedHue(role: RoleDefinitionInterfaceType): number {
  if (role.hue !== undefined) {
    return (((role.hue % 360) + 360) % 360);
  }
  return role.hueOffset ?? 0;
}

function synthesizeForRole(role: RoleDefinitionInterfaceType): ColorRecordInterfaceType {
  const l = role.lightnessRange !== undefined ? rangeCenter(role.lightnessRange) : 0.5;
  const c = role.chromaRange    !== undefined ? rangeCenter(role.chromaRange)    : 0;
  const h = synthesizedHue(role);
  const hints: ColorHintsInterfaceType | undefined = role.intent !== undefined
    ? { 'intent': role.intent }
    : undefined;
  return colorRecordFactory.fromOklch(l, c, h, { 'alpha': 1, 'hints': hints, 'sourceFormat': 'oklch' });
}

/**
 * Pipeline task that assigns one `ColorRecord` to each non-derived
 * role in the schema. Resolution order:
 *   1. Hint match: a color carrying `hints.role === <name>` wins.
 *   2. No candidates available: `required` roles are synthesised
 *      from the role's own range centers.
 *   3. Closest by OKLCH distance to the range center.
 *
 * In all cases the assigned color is then nudged into the declared
 * `lightnessRange` / `chromaRange` (and exact `hueOffset` if set), so
 * required roles are guaranteed to satisfy their constraints. Roles
 * that had to be synthesised are recorded in
 * `state.metadata['core:rolesSynthesized']` for diagnostics.
 *
 * Roles with `derivedFrom` are deferred to {@link ExpandFamily} and
 * skipped here.
 */
class ResolveRoles implements TaskInterface {
  readonly 'name' = 'resolve:roles';

  readonly 'manifest': TaskManifestInterfaceType = {
    'description': 'Assigns colors to schema roles by hint match then OKLCH distance to range center, then nudges the assigned color into the role\'s declared ranges. Required roles are guaranteed populated and constraint-satisfying.',
    'name':        'resolve:roles',
    'reads':       ['colors', 'input.roles'],
    'writes':      ['roles', 'metadata']
  };

  run(state: PaletteStateInterface, ctx: PipelineContextInterface): void {
    if (state.input.roles === undefined) {
      ctx.logger.debug(
        LogBody.create()
          .component('ResolveRoles')
          .operation('run')
          .status(LOG_STATUS.SKIPPED)
          .message('No role schema provided; skipping')
          .context({})
          .build()
      );
      return;
    }

    const schema = state.input.roles;
    const synthesized: string[] = [];

    for (const role of schema.roles) {
      if (role.derivedFrom !== undefined && role.derivedFrom.length > 0) {
        continue;
      }

      // Hint match takes priority: explicit user intent.
      const hintMatch = state.colors.find((c) => {return c.hints?.role === role.name;});
      if (hintMatch !== undefined) {
        const resolved = nudgeIntoRole(hintMatch, role);
        state.roles[role.name] = resolved;

        const isClamped = Math.abs(hintMatch.oklch.l - resolved.oklch.l) > 0.005 ||
                          Math.abs(hintMatch.oklch.c - resolved.oklch.c) > 0.005 ||
                          Math.abs(hintMatch.oklch.h - resolved.oklch.h) > 0.5;

        if (isClamped) {
          if (!state.metadata['core:roleClamps']) {
            state.metadata['core:roleClamps'] = {};
          }
          (state.metadata['core:roleClamps'] as Record<string, any>)[role.name] = {
            'seedHex': hintMatch.hex,
            'seedOklch': hintMatch.oklch,
            'resolvedHex': resolved.hex,
            'resolvedOklch': resolved.oklch
          };
        }

        ctx.logger.debug(
          LogBody.create()
            .component('ResolveRoles')
            .operation('run')
            .status(LOG_STATUS.SUCCESS)
            .message('Role assigned by hint match')
            .context({ 'role': role.name })
            .build()
        );
        continue;
      }

      // No candidate colors at all: synthesize required roles from constraints.
      if (state.colors.length === 0) {
        if (role.required === true) {
          state.roles[role.name] = synthesizeForRole(role);
          synthesized.push(role.name);
          ctx.logger.debug(
            LogBody.create()
              .component('ResolveRoles')
              .operation('run')
              .status(LOG_STATUS.PARTIAL)
              .message('Role synthesized from constraints; no input colors')
              .context({ 'role': role.name })
              .build()
          );
        }
        continue;
      }

      // Pick closest candidate by distance to constraint center.
      let best: ColorRecordInterfaceType | undefined;
      let bestDist = Infinity;
      const distances: Record<string, number> = {};

      for (const color of state.colors) {
        const dist = distanceToRoleCenter(color, role);
        distances[color.hex] = dist;
        if (dist < bestDist) {
          bestDist = dist;
          best = color;
        }
      }

      if (!state.metadata['core:roleDistances']) {
        state.metadata['core:roleDistances'] = {};
      }
      (state.metadata['core:roleDistances'] as Record<string, any>)[role.name] = distances;

      // Nudge the candidate into the role's ranges so required roles are
      // guaranteed to satisfy lightnessRange, chromaRange, and hueOffset.
      if (best !== undefined) {
        const resolved = nudgeIntoRole(best, role);
        state.roles[role.name] = resolved;

        const isClamped = Math.abs(best.oklch.l - resolved.oklch.l) > 0.005 ||
                          Math.abs(best.oklch.c - resolved.oklch.c) > 0.005 ||
                          Math.abs(best.oklch.h - resolved.oklch.h) > 0.5;

        if (isClamped) {
          if (!state.metadata['core:roleClamps']) {
            state.metadata['core:roleClamps'] = {};
          }
          (state.metadata['core:roleClamps'] as Record<string, any>)[role.name] = {
            'seedHex': best.hex,
            'seedOklch': best.oklch,
            'resolvedHex': resolved.hex,
            'resolvedOklch': resolved.oklch
          };
        }

        ctx.logger.debug(
          LogBody.create()
            .component('ResolveRoles')
            .operation('run')
            .status(LOG_STATUS.SUCCESS)
            .message('Role assigned by distance and nudged into range')
            .context({
              'distance': bestDist,
              'role':     role.name
            })
            .build()
        );
      } else if (role.required === true) {
        // Defensive: state.colors was non-empty above, so this only fires
        // if every distance computation produced Infinity. Synthesise to
        // honour the required contract.
        state.roles[role.name] = synthesizeForRole(role);
        synthesized.push(role.name);
      }
    }

    if (synthesized.length > 0) {
      const existing = state.metadata['core:rolesSynthesized'];
      const prior: string[] = Array.isArray(existing) ? (existing as string[]) : [];
      state.metadata['core:rolesSynthesized'] = [...prior, ...synthesized];
    }
  }
}

