    0.152286, 1.052583, -0.204868,
    0.114503, 0.786281,  0.099216,
    -0.003882, -0.048116,  1.051998
  ],
  'name':   'protanopia'
};

/** Deuteranopia: M-cone (green) absent. [VBM99] Table 1, normalised. */
const deuteranopiaMatrix: CvdMatrixInterfaceType = {
