    -0.011820,  0.042940,  0.968881
  ],
  'name':   'deuteranopia'
};

/** Tritanopia: S-cone (blue) absent. [BVM97] two-half-plane model. */
const tritanopiaMatrix: CvdMatrixInterfaceType = {
