  readonly 'name' = 'intake:hexHint';

  readonly 'manifest': TaskManifestInterfaceType = {
    'description': 'Parses hex strings or {hex, role} pin objects into ColorRecords, attaching hints.role when a role is pinned.',
    'name':        'intake:hexHint',
    'reads':       ['input.colors'],
    'writes':      ['colors']
  };

